import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import './App.css';
import { marked } from 'marked';

function App() {
  // State declarations
  const [user, setUser] = useState(null);
  const [input, setInput] = useState('');
  const [chatHistory, setChatHistory] = useState([]);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isHybridPlanModalOpen, setIsHybridPlanModalOpen] = useState(false);
  const [isContactAgentModalOpen, setIsContactAgentModalOpen] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState([]);
  const [showFileUpload, setShowFileUpload] = useState(false);
  const [isLanguageDropdownOpen, setIsLanguageDropdownOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [agents, setAgents] = useState([]);

  // Memoized API functions
  const fetchChatHistory = useCallback(async (userId) => {
    try {
      const response = await axios.get('/api/chats', {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      setChatHistory(response.data.map(chat => ({
        role: chat.user === userId ? 'user' : 'ai',
        content: chat.message || chat.response,
        timestamp: chat.createdAt
      })));
    } catch (error) {
      console.error('Failed to fetch chat history:', error);
    }
  }, []);

  const fetchAgents = useCallback(async () => {
    try {
      const response = await axios.get('/api/agents');
      setAgents(response.data);
    } catch (error) {
      console.error('Failed to fetch agents:', error);
    }
  }, []);

  const verifyToken = useCallback(async (token) => {
    try {
      const response = await axios.get('/api/verify-token', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUser(response.data.user);
      fetchChatHistory(response.data.user._id);
    } catch (error) {
      localStorage.removeItem('token');
      console.error('Token verification failed:', error);
    }
  }, [fetchChatHistory]);

  // Initialization effect
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      verifyToken(token);
    }
    fetchAgents();
  }, [verifyToken, fetchAgents]);

  // Handler functions
  const handleLogin = async () => {
    try {
      const response = await axios.post('/api/login', { email, password });
      localStorage.setItem('token', response.data.token);
      setUser(response.data.user);
      setIsAuthModalOpen(false);
      addMessage('ai', `Welcome back, ${response.data.user.name}! How can I assist with your immigration needs today?`);
    } catch (error) {
      alert(error.response?.data?.error || 'Login failed. Please check your credentials.');
    }
  };

  const handleRegister = async () => {
    if (password !== confirmPassword) {
      alert('Passwords do not match');
      return;
    }
    
    try {
      const response = await axios.post('/api/register', { name, email, password });
      localStorage.setItem('token', response.data.token);
      setUser(response.data.user);
      setIsAuthModalOpen(false);
      addMessage('ai', `Welcome to AI-MMI, ${response.data.user.name}! Let's get started with your immigration journey.`);
    } catch (error) {
      alert(error.response?.data?.error || 'Registration failed. Please try again.');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setUser(null);
    addMessage('ai', "You have been logged out. Please log in again to access your profile.");
  };

  const addMessage = (role, content) => {
    const newMessage = {
      role,
      content,
      timestamp: new Date().toISOString()
    };
    setChatHistory(prev => [...prev, newMessage]);
  };

  const handleFileSelect = (e) => {
    const files = Array.from(e.target.files);
    const validFiles = files.filter(file => file.size <= 5 * 1024 * 1024);
    
    if (validFiles.length !== files.length) {
      alert('Some files were too large (max 5MB) and were not added.');
    }
    
    setUploadedFiles(prev => [...prev, ...validFiles]);
    e.target.value = '';
  };

  const removeFile = (index) => {
    const newFiles = [...uploadedFiles];
    newFiles.splice(index, 1);
    setUploadedFiles(newFiles);
  };

  const handleSendMessage = async () => {
    if (!input && uploadedFiles.length === 0) return;
    
    addMessage('user', input);
    setInput('');
    setShowFileUpload(false);
    setIsProcessing(true);
    
    try {
      const formData = new FormData();
      formData.append('message', input);
      uploadedFiles.forEach(file => formData.append('files', file));

      const config = {
        headers: {
          'Content-Type': 'multipart/form-data',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        }
      };

      const response = await axios.post('/api/chat', formData, config);
      addMessage('ai', response.data.response);
      setUploadedFiles([]);
    } catch (error) {
      console.error('Error sending message:', error);
      addMessage('ai', "Sorry, I encountered an error processing your request. Please try again later.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') handleSendMessage();
  };

  const handleLanguageChange = (language) => {
    alert(`Language changed to ${language}`);
    setIsLanguageDropdownOpen(false);
  };

  const showUserProfile = () => {
    alert("My Profile feature is not implemented yet.");
  };

  // JSX rendering
  return (
    <div className="app-container">
      <header className="header">
        <div className="header-brand">
          <img 
            src="https://i.ibb.co/pjR8wxhR/ai-mmi-logo-dark-background.png" 
            alt="AI-MMI Logo" 
            className="header-icon" 
          />
          <h1 className="header-title">AI-MMI</h1>
        </div>
        
        <div className="header-controls">
          <div className="language-dropdown">
            <img 
              src="https://i.ibb.co/tMDdT4bd/icon-lang.png" 
              alt="Language" 
              className="header-icon" 
              onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}
              role="button"
              tabIndex="0"
            />
            {isLanguageDropdownOpen && (
              <div className="language-options">
                <button onClick={() => handleLanguageChange('English')}>English</button>
                <button onClick={() => handleLanguageChange('Chinese')}>中文</button>
                <button onClick={() => handleLanguageChange('Spanish')}>Español</button>
                <button onClick={() => handleLanguageChange('French')}>Français</button>
              </div>
            )}
          </div>
          <img 
            src={user ? "https://i.imgur.com/FcJiNT7.png" : "https://i.ibb.co/3mmnZvWc/icon-member.png"} 
            alt="User" 
            className="header-icon" 
            onClick={user ? handleLogout : () => setIsAuthModalOpen(true)}
            role="button"
            tabIndex="0"
          />
        </div>
      </header>

      <div className="main-content">
        <div className="chat-container">
          <div className="chat-history">
            {chatHistory.length === 0 ? (
              <div className="welcome-message">
                <h2>Welcome to AI-MMI Immigration Assistant</h2>
                <p>Ask me anything about visas, immigration processes, or upload your documents for analysis.</p>
              </div>
            ) : (
              chatHistory.map((msg, index) => (
                <div key={index} className={`message ${msg.role}-message`}>
                  <div dangerouslySetInnerHTML={{ __html: marked.parse(msg.content) }} />
                  <div className="timestamp">{new Date(msg.timestamp).toLocaleTimeString()}</div>
                </div>
              ))
            )}
            {isProcessing && (
              <div className="message ai-message">
                <div className="text-center">
                  <div className="spinner-border spinner-border-sm" role="status"></div> Processing...
                </div>
              </div>
            )}
          </div>
          
          <div className="input-area">
            {showFileUpload && (
              <div className="file-upload-container">
                <div className="file-previews">
                  {uploadedFiles.map((file, index) => (
                    <div key={index} className="file-preview">
                      <i className={`fas ${
                        file.type === 'application/pdf' ? 'fa-file-pdf' :
                        file.type.includes('word') ? 'fa-file-word' :
                        file.type === 'text/plain' ? 'fa-file-alt' :
                        file.type.includes('image') ? 'fa-file-image' : 'fa-file'
                      } file-icon`}></i>
                      <span className="file-name">{file.name}</span>
                      <button 
                        className="btn btn-sm btn-outline-danger"
                        onClick={() => removeFile(index)}
                      >
                        <i className="fas fa-times"></i>
                      </button>
                    </div>
                  ))}
                </div>
                <label htmlFor="fileUpload" className="btn btn-custom-outline btn-sm">
                  <i className="fas fa-plus"></i> Add Files
                </label>
                <input 
                  type="file" 
                  id="fileUpload" 
                  multiple 
                  style={{ display: 'none' }} 
                  onChange={handleFileSelect}
                  accept=".pdf,.doc,.docx,.txt,.png,.jpg,.jpeg"
                />
                <p className="small mt-2 mb-0">Supported: PDF, Word, TXT, PNG, JPG (Max 5MB each)</p>
              </div>
            )}
            
            <div className="input-group">
              <button 
                className="btn btn-custom-outline mr-2" 
                onClick={() => setShowFileUpload(!showFileUpload)}
              >
                <i className="fas fa-paperclip"></i>
              </button>
              <input 
                type="text" 
                className="form-control" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder="Type your question here..." 
              />
              <button 
                className="btn btn-custom ml-2" 
                onClick={handleSendMessage}
                disabled={!input && uploadedFiles.length === 0}
              >
                <i className="fas fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>
        
        <div className="sidebar">
          <div className="sidebar-container">
            <div className="promo-banner">
              <button 
                className="btn btn-custom" 
                onClick={() => setIsContactAgentModalOpen(true)}
              >
                Contact a Migration Lawyer/Agent
              </button>
            </div>
            <div className="sidebar-item" onClick={() => alert('Free assessment clicked')}>
              <span className="sidebar-icon"></span> Free assessment
            </div>
            <div className="sidebar-item" onClick={() => alert('Search chats clicked')}>
              <span className="sidebar-icon"></span> Search chats
            </div>
            <div className="sidebar-item" onClick={() => user ? showUserProfile() : setIsAuthModalOpen(true)}>
              <span className="sidebar-icon"></span> My profile
            </div>
            <div className="sidebar-item" onClick={() => user ? alert('My documents clicked') : setIsAuthModalOpen(true)}>
              <span className="sidebar-icon"></span> My documents
            </div>
            <div className="sidebar-item" onClick={() => alert('AI-MMI recommendations clicked')}>
              <span className="sidebar-icon"></span> AI-MMI's recommendations
            </div>
            
            <div className="promo-banner">
              <button 
                className="btn btn-custom" 
                onClick={() => setIsHybridPlanModalOpen(true)}
              >
                Subscribe for Hybrid Plan
              </button>
            </div>
          </div>
        </div>
      </div>

      {isAuthModalOpen && (
        <div className="modal-overlay">
          <div className="auth-modal">
            <div className="auth-tabs">
              <div 
                className={`auth-tab ${isLogin ? 'active' : ''}`} 
                onClick={() => setIsLogin(true)}
              >
                Login
              </div>
              <div 
                className={`auth-tab ${!isLogin ? 'active' : ''}`} 
                onClick={() => setIsLogin(false)}
              >
                Sign Up
              </div>
            </div>
            
            {isLogin ? (
              <div className="auth-form active">
                <div className="form-group">
                  <label htmlFor="loginEmail">Email</label>
                  <input 
                    type="email" 
                    id="loginEmail" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Enter your email" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="loginPassword">Password</label>
                  <input 
                    type="password" 
                    id="loginPassword" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Enter your password" 
                  />
                </div>
                <div className="auth-actions">
                  <button 
                    className="btn btn-custom-outline" 
                    onClick={() => setIsAuthModalOpen(false)}
                  >
                    Cancel
                  </button>
                  <button 
                    className="btn btn-custom" 
                    onClick={handleLogin}
                  >
                    Login
                  </button>
                </div>
              </div>
            ) : (
              <div className="auth-form">
                <div className="form-group">
                  <label htmlFor="signupName">Full Name</label>
                  <input 
                    type="text" 
                    id="signupName" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Enter your full name" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="signupEmail">Email</label>
                  <input 
                    type="email" 
                    id="signupEmail" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Enter your email" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="signupPassword">Password</label>
                  <input 
                    type="password" 
                    id="signupPassword" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Create a password" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="signupConfirmPassword">Confirm Password</label>
                  <input 
                    type="password" 
                    id="signupConfirmPassword" 
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    placeholder="Confirm your password" 
                  />
                </div>
                <div className="auth-actions">
                  <button 
                    className="btn btn-custom-outline" 
                    onClick={() => setIsAuthModalOpen(false)}
                  >
                    Cancel
                  </button>
                  <button 
                    className="btn btn-custom" 
                    onClick={handleRegister}
                  >
                    Sign Up
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {isHybridPlanModalOpen && (
        <div className="hybrid-plan-modal">
          <div className="hybrid-plan-container">
            <div className="hybrid-plan-header">
              <h2>Choose Your Hybrid Plan</h2>
              <button 
                className="hybrid-plan-close" 
                onClick={() => setIsHybridPlanModalOpen(false)}
                aria-label="Close modal"
              >
                &times;
              </button>
            </div>
            <div className="hybrid-plan-body">
              <p>Upgrade to a Hybrid Plan to get the best of both worlds - AI assistance combined with expert human support for your immigration needs.</p>
              
              <div className="plan-cards">
                <div className="plan-card plan-card-basic">
                  <div className="plan-card-header">
                    <h3>Basic Plan</h3>
                    <p>For simple immigration queries</p>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Unlimited AI chat assistance</li>
                      <li><i className="fas fa-check"></i> Document analysis (up to 5/month)</li>
                      <li><i className="fas fa-check"></i> Basic visa eligibility check</li>
                      <li><i className="fas fa-check"></i> Email support (72h response)</li>
                      <li><i className="fas fa-times"></i> No human agent access</li>
                    </ul>
                    <div className="plan-price">
                      $9.99 <span>/ month</span>
                    </div>
                    <button 
                      className="plan-select-btn" 
                      onClick={() => {
                        if (!user) {
                          setIsHybridPlanModalOpen(false);
                          setIsAuthModalOpen(true);
                          alert('Please login or sign up to subscribe to a plan');
                        } else {
                          alert('Thank you for selecting the Basic Plan! You will be redirected to payment.');
                          setIsHybridPlanModalOpen(false);
                        }
                      }}
                    >
                      Select Basic Plan
                    </button>
                  </div>
                </div>
                
                <div className="plan-card plan-card-premium">
                  <div className="plan-card-header">
                    <h3>Premium Plan</h3>
                    <p>Most popular choice</p>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Everything in Basic</li>
                      <li><i className="fas fa-check"></i> Priority AI responses</li>
                      <li><i className="fas fa-check"></i> Document analysis (unlimited)</li>
                      <li><i className="fas fa-check"></i> 2 consultations with agent/month</li>
                      <li><i className="fas fa-check"></i> Email support (24h response)</li>
                    </ul>
                    <div className="plan-price">
                      $29.99 <span>/ month</span>
                    </div>
                    <button 
                      className="plan-select-btn" 
                      onClick={() => {
                        if (!user) {
                          setIsHybridPlanModalOpen(false);
                          setIsAuthModalOpen(true);
                          alert('Please login or sign up to subscribe to a plan');
                        } else {
                          alert('Thank you for selecting the Premium Plan! You will be redirected to payment.');
                          setIsHybridPlanModalOpen(false);
                        }
                      }}
                    >
                      Select Premium Plan
                    </button>
                  </div>
                </div>
                
                <div className="plan-card plan-card-platinum">
                  <div className="plan-card-header">
                    <h3>Platinum Plan</h3>
                    <p>For complex cases</p>
                  </div>
                  <div className="plan-card-body">
                    <ul className="plan-features">
                      <li><i className="fas fa-check"></i> Everything in Premium</li>
                      <li><i className="fas fa-check"></i> Unlimited agent consultations</li>
                      <li><i className="fas fa-check"></i> Document review by agents</li>
                      <li><i className="fas fa-check"></i> Application preparation help</li>
                      <li><i className="fas fa-check"></i> Priority 24/7 support</li>
                    </ul>
                    <div className="plan-price">
                      $99.99 <span>/ month</span>
                    </div>
                    <button 
                      className="plan-select-btn" 
                      onClick={() => {
                        if (!user) {
                          setIsHybridPlanModalOpen(false);
                          setIsAuthModalOpen(true);
                          alert('Please login or sign up to subscribe to a plan');
                        } else {
                          alert('Thank you for selecting the Platinum Plan! You will be redirected to payment.');
                          setIsHybridPlanModalOpen(false);
                        }
                      }}
                    >
                      Select Platinum Plan
                    </button>
                  </div>
                </div>
              </div>
              
              <div className="hybrid-plan-footer">
                <p>All plans come with a 7-day money back guarantee. Cancel anytime.</p>
                <button 
                  className="back-to-home-button"
                  onClick={() => setIsHybridPlanModalOpen(false)}
                >
                  <i className="fas fa-arrow-left"></i> Back to Home
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {isContactAgentModalOpen && (
        <div className="contact-agent-modal">
          <div className="contact-agent-container">
            <div className="contact-agent-header">
              <h2>Contact a Migration Expert</h2>
              <button 
                className="contact-agent-close" 
                onClick={() => setIsContactAgentModalOpen(false)}
                aria-label="Close modal"
              >
                &times;
              </button>
            </div>
            <div className="contact-agent-body">
              <p>Connect with our network of registered migration agents and lawyers for personalized assistance with your case.</p>
              
              {agents.length > 0 ? (
                <>
                  <div className="country-section">
                    <h3 className="country-title">Australia</h3>
                    <div className="agent-cards">
                      {agents.filter(agent => agent.countries.includes("Australia")).map(agent => (
                        <div key={`aus-${agent._id}`} className="agent-card">
                          <div className="agent-card-header">
                            <h4 className="agent-company">{agent.company}</h4>
                          </div>
                          <div className="agent-card-body">
                            <div className="agent-details">
                              <p><i className="fas fa-phone"></i> {agent.phone}</p>
                              <p><i className="fas fa-envelope"></i> {agent.email}</p>
                              {agent.website && <p><i className="fas fa-globe"></i> {agent.website}</p>}
                            </div>
                            <button 
                              className="agent-contact-btn" 
                              onClick={() => {
                                if (!user) {
                                  setIsContactAgentModalOpen(false);
                                  setIsAuthModalOpen(true);
                                  alert('Please login or sign up to contact an agent');
                                } else {
                                  alert(`Connecting you with ${agent.company}...`);
                                }
                              }}
                            >
                              Contact Agent
                            </button>
                            {agent.registration && (
                              <div style={{ marginTop: '10px' }}>
                                <p className="agent-name">{agent.name}</p>
                                <p className="agent-registration">Registration: {agent.registration}</p>
                              </div>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </>
              ) : (
                <p>Loading agents...</p>
              )}
              
              <div className="contact-agent-footer">
                <p>All our agents are registered with the appropriate regulatory bodies in their jurisdictions.</p>
                <button 
                  className="back-to-home-button"
                  onClick={() => setIsContactAgentModalOpen(false)}
                >
                  <i className="fas fa-arrow-left"></i> Back to Home
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
